/*!
** @file IOUPserial.c
** @version 01.02
** @brief
**         This component "AsynchroSerial" implements an asynchronous serial
**         communication. The component supports different settings of
**         parity, word width, stop-bit and communication speed,
**         user can select interrupt or polling handler.
**         Communication speed can be changed also in runtime.
**         The component requires one on-chip asynchronous serial channel.
*/         
/*!
**  @addtogroup IOUPserial_module IOUPserial module documentation
**  @{
*/         

/* MODULE IOUPserial. */

#include "IOUPserial.h"
#include "Events.h"


#define OVERRUN_ERR      0x01          /* Overrun error flag bit    */
#define FRAMING_ERR      0x02          /* Framing error flag bit    */
#define PARITY_ERR       0x04          /* Parity error flag bit     */
#define CHAR_IN_RX       0x08          /* Char is in RX buffer      */
#define FULL_TX          0x10          /* Full transmit buffer      */
#define RUNINT_FROM_TX   0x20          /* Interrupt is in progress  */
#define FULL_RX          0x40          /* Full receive buffer       */
#define ENABLED_TX_INT   0x80          /* TX interrupt enabled      */
#define BREAK_ERR        0x0200        /* Break detect              */

volatile bool EnEvent;                 /* Enable/Disable events */
static volatile word SerFlag;          /* Flags for serial communication */
                                       /* Bits: 0 - OverRun error */
                                       /*       1 - Framing error */
                                       /*       2 - Parity error */
                                       /*       3 - Char in RX buffer */
                                       /*       4 - Full TX buffer */
                                       /*       5 - Running int from TX */
                                       /*       6 - Full RX buffer */
                                       /*       7 - TX interrupt enabled */
                                       /*       8 - Unused  */
                                       /*       9 - Break detected  */
                                       /*      10 - Unused */
                                       /*      11 - Unused */
static volatile word ErrFlag;          /* Error flags mirror of SerFlag */
volatile word IOUPserial_InpLen;       /* Length of input buffer's content */
static volatile IOUPserial_TComData *InpPtrR; /* Pointer for reading from input buffer */
static volatile IOUPserial_TComData *InpPtrW; /* Pointer for writing to input buffer */
static volatile IOUPserial_TComData InpBuffer[IOUPserial_INP_BUF_SIZE]; /* Input buffer for serial commmunication */
volatile word IOUPserial_OutLen;       /* Length of output bufer's content */
static volatile IOUPserial_TComData *OutPtrR; /* Pointer for reading from output buffer */
static volatile IOUPserial_TComData *OutPtrW; /* Pointer for writing to output buffer */
static volatile IOUPserial_TComData OutBuffer[IOUPserial_OUT_BUF_SIZE]; /* Output buffer for serial commmunication */

/*
** ===================================================================
**     Method      :  HWEnDi (component AsynchroSerial)
**
**     Description :
**         Enables or disables the peripheral(s) associated with the 
**         component. The method is called automatically as a part of the 
**         Enable and Disable methods and several internal methods.
**         This method is internal. It is used by Processor Expert only.
** ===================================================================
*/
static void HWEnDi(void)
{
  setReg8(UCR0, (UCR0_TC0_BITMASK | UCR0_RC0_BITMASK)); /* Enable receiver and transmitter */
  setReg8(UIMR0, 0x02);                /* Enable receiver interrupt */
}

