/*
** ===================================================================
**     Method      :  IOUPserial_GetError (component AsynchroSerial)
**     Description :
**         Returns a set of errors on the channel (errors that cannot
**         be returned by given methods). The errors accumulate in a
**         set; after calling [GetError] this set is returned and
**         cleared.
**     Parameters  :
**         NAME            - DESCRIPTION
**       * Err             - Pointer to the returned set of errors
**     Returns     :
**         ---             - Error code (if GetError did not succeed),
**                           possible codes:
**                           ERR_OK - OK
**                           ERR_SPEED - This device does not work in
**                           the active speed mode
** ===================================================================
*/
byte IOUPserial_GetError(IOUPserial_TError *Err)
{
  EnterCritical();                     /* Disable global interrupts */
  Err->err = 0;
  Err->errName.OverRun = ((ErrFlag & OVERRUN_ERR) != 0x00); /* Overrun error */
  Err->errName.Framing = ((ErrFlag & FRAMING_ERR ) != 0x00); /* Framing error */
  Err->errName.Parity = ((ErrFlag & PARITY_ERR) != 0x00); /* Parity error */
  Err->errName.RxBufOvf = ((ErrFlag & FULL_RX) != 0x00); /* Buffer overflow */
  ErrFlag = 0;                         /* Clear error flags */
  ExitCritical();                      /* Enable global interrupts */
  return ERR_OK;                       /* OK */
}

/*
** ===================================================================
**     Method      :  IOUPserial_InterruptRx (component AsynchroSerial)
**
**     Description :
**         The method services the receive interrupt of the selected 
**         peripheral(s) and eventually invokes the component's event(s).
**         This method is internal. It is used by Processor Expert only.
** ===================================================================
*/
#define ON_ERROR    1
#define ON_FULL_RX  2
#define ON_RX_CHAR  4
static void IOUPserial_InterruptRx(void)
{
  register IOUPserial_TComData Data;   /* Temporary variable for data */
  register byte OnFlags = 0x00;        /* Temporary variable for flags */

  Data = (IOUPserial_TComData)getReg8(URB0); /* Read data from the receiver */
  if (IOUPserial_InpLen < IOUPserial_INP_BUF_SIZE) { /* Is number of bytes in the receive buffer lower than size of buffer? */
    IOUPserial_InpLen++;               /* Increse number of chars in the receive buffer */
    *(InpPtrW++) = Data;               /* Save received char to the receive buffer */
    if (InpPtrW >= (InpBuffer + IOUPserial_INP_BUF_SIZE)) { /* Is the pointer out of the receive buffer? */
      InpPtrW = InpBuffer;             /* Set pointer on the first item into the receive buffer */
    }
    OnFlags |= ON_RX_CHAR;             /* Set flag "OnRXChar" */
    if (IOUPserial_InpLen == IOUPserial_INP_BUF_SIZE) { /* Is number of bytes in the receive buffer equal as a size of buffer? */
      OnFlags |= ON_FULL_RX;           /* If yes then set flag "OnFullRxBuff" */
    }
  } else {
    SerFlag |= FULL_RX;                /* If yes then set flag buffer overflow */
    ErrFlag |= FULL_RX;
    OnFlags |= ON_ERROR;               /* Set flag "OnError" */
  }
  if (EnEvent) {                       /* Are the events enabled? */
    if (OnFlags & ON_ERROR) {          /* Is error flag set? */
      IOUPserial_OnError();            /* If yes then invoke user event */
    } else {
      if (OnFlags & ON_RX_CHAR) {      /* Is OnRxChar flag set? */
        IOUPserial_OnRxChar();         /* If yes then invoke user event */
      }
      if (OnFlags & ON_FULL_RX) {      /* Is OnFullRxBuf flag set? */
        IOUPserial_OnFullRxBuf();      /* If yes then invoke user event */
      }
    }
  }
}

/*
** ===================================================================
**     Method      :  IOUPserial_InterruptTx (component AsynchroSerial)
**
**     Description :
**         The method services the receive interrupt of the selected 
**         peripheral(s) and eventually invokes the component's event(s).
**         This method is internal. It is used by Processor Expert only.
** ===================================================================
*/
#define ON_FREE_TX  1
#define ON_TX_CHAR  2
static void IOUPserial_InterruptTx(void)
{
  register byte OnFlags = 0x00;        /* Temporary variable for flags */

  if (SerFlag & RUNINT_FROM_TX) {      /* Is flag "running int from TX" set? */
    OnFlags |= ON_TX_CHAR;             /* Set flag "OnTxChar" */
  }
  SerFlag &= ~RUNINT_FROM_TX;          /* Reset flag "running int from TX" */
  if (IOUPserial_OutLen) {             /* Is number of bytes in the transmit buffer greater then 0? */
    IOUPserial_OutLen--;               /* Decrease number of chars in the transmit buffer */
    SerFlag |= RUNINT_FROM_TX;         /* Set flag "running int from TX"? */
    setReg8(UTB0, (IOUPserial_TComData)*(OutPtrR++)); /* Store char to transmitter register */
    if (OutPtrR >= (OutBuffer + IOUPserial_OUT_BUF_SIZE)) { /* Is the pointer out of the transmit buffer? */
      OutPtrR = OutBuffer;             /* Set pointer on the first item into the transmit buffer */
    }
  } else {
    OnFlags |= ON_FREE_TX;             /* Set flag "OnFreeTxBuf" */
    SerFlag &= ~ENABLED_TX_INT;        /* Clear the flag ENABLED_TX_INT */
    setReg8(UIMR0, 0x02);              /* Disable transmit interrupt */
  }
  ErrFlag |= SerFlag;                  /* Add new error flags into the ErrorFlag status variable */
  if (EnEvent) {                       /* Are the events enabled? */
    if (OnFlags & ON_TX_CHAR) {        /* Is flag "OnTxChar" set? */
      IOUPserial_OnTxChar();           /* If yes then invoke user event */
    }
    if (OnFlags & ON_FREE_TX) {        /* Is flag "OnFreeTxBuf" set? */
      IOUPserial_OnFreeTxBuf();        /* If yes then invoke user event */
    }
  }
}

/*
** ===================================================================
**     Method      :  IOUPserial_Interrupt (component AsynchroSerial)
**
**     Description :
**         This method is internal. It is used by Processor Expert only.
** ===================================================================
*/
__declspec(interrupt) void IOUPserial_Interrupt(void)
{
  register word StatReg = getReg8(USR0); /* Read status register */
  register word OnFlags = 0;           /* Temporary variable for flags */

  if (StatReg & (USR0_RB_BITMASK | USR0_OE_BITMASK | USR0_FE_BITMASK | USR0_PE_BITMASK)) { /* Is any error flag set? */
    setReg8(UCR0, 0x40);               /* Reset error request flags */
    if (StatReg & USR0_RB_BITMASK) {   /* Is break detected? */
      OnFlags |= FRAMING_ERR;          /* If yes then set the flag */
    }
    if (StatReg & USR0_OE_BITMASK) {   /* Is overrun error flag set? */
      OnFlags |= OVERRUN_ERR;          /* If yes then set the flag */
    }
    if (StatReg & USR0_FE_BITMASK) {   /* Is framing error flag set? */
      OnFlags |= FRAMING_ERR;          /* If yes then set the flag */
    }
    if (StatReg & USR0_PE_BITMASK) {   /* Is parity error flag set? */
      OnFlags |= PARITY_ERR;           /* If yes then set the flag */
    }
    SerFlag |= OnFlags;                /* Copy flags status to SerFlag status variable */
    ErrFlag |= OnFlags;                /* Copy flags status to ErrFlag status variable */
    (void)getReg8(URB0);               /* Dummy read of data register - clear RXRDY bit */
    StatReg &= ~USR0_RXRDY_BITMASK;    /* Clear the receive data flag to discard the errorneous data */
    if (EnEvent) {                     /* Are the events enabled? */
      IOUPserial_OnError();            /* If yes then invoke user event */
    }
  }
  if (StatReg & USR0_RXRDY_BITMASK) {  /* Is the receiver interrupt flag set? */
    IOUPserial_InterruptRx();          /* If yes, then invoke the internal service routine. This routine is inlined. */
  }
  if (SerFlag & ENABLED_TX_INT) {      /* Is the transmitter interrupt enabled? */
    if (StatReg & USR0_TXRDY_BITMASK) { /* Is the transmitter ready? */
      IOUPserial_InterruptTx();        /* If yes, then invoke the internal service routine. This routine is inlined. */
    }
  }
}

/*
** ===================================================================
**     Method      :  IOUPserial_Init (component AsynchroSerial)
**
**     Description :
**         Initializes the associated peripheral(s) and the component 
**         internal variables. The method is called automatically as a 
**         part of the application initialization code.
**         This method is internal. It is used by Processor Expert only.
** ===================================================================
*/
void IOUPserial_Init(void)
{
  SerFlag = 0x00;                      /* Reset flags */
  EnEvent = FALSE;                     /* Disable events */
  /* UCR0: ??=0,MISC=3,TC=0,RC=0 */
  setReg8(UCR0, 0x30U);                /* Reset UART transmitter */ 
  /* UCR0: ??=0,MISC=2,TC=0,RC=0 */
  setReg8(UCR0, 0x20U);                /* Reset UART receiver */ 
  /* UMR10: RXRTS=0,RXIRQ=0,ERR=0,PM=2,PT=0,BC=3 */
  setReg8(UMR10, 0x13U);               /*  Set the UMR1 register */ 
  /* UMR20: CM=0,TXRTS=0,TXCTS=0,SB=7 */
  setReg8(UMR20, 0x07U);               /*  Set the UMR2 register */ 
  /* UCSR0: RCS=0x0D,TCS=0x0D */
  setReg8(UCSR0, 0xDDU);                
  IOUPserial_InpLen = 0x00;            /* No char in the receive buffer */
  InpPtrW = InpPtrR = InpBuffer;       /* Set pointer on the first item in the receive buffer */
  IOUPserial_OutLen = 0x00;            /* No char in the transmit buffer */
  OutPtrW = OutPtrR = OutBuffer;       /* Set pointer on the first item in the transmit buffer */
  /* UBG10: Divider_MSB=0 */
  setReg8(UBG10, 0x00U);                
  /* UBG20: Divider_LSB=0x51 */
  setReg8(UBG20, 0x51U);                
  HWEnDi();                            /* Enable/disable device according to status flags */
}

